module traffic_light #(
    parameter idle = 2'd0,
    parameter s1_red = 2'd1,
    parameter s2_yellow = 2'd2,
    parameter s3_green = 2'd3
) (
    input rst_n,
    input clk,
    input pass_request,
    output wire[7:0]clock,
    output reg red,
    output reg yellow,
    output reg green
);

reg [7:0] cnt;
reg state;

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        cnt <= 0;
        state <= idle;
    end else begin
        case (state)
            idle: begin
                cnt <= 0;
                state <= s1_red;
            end
            s1_red: begin
                if (pass_request && cnt >= 10)
                    state <= s2_yellow;
                else if (cnt == 0)
                    state <= s1_red;
                    cnt <= cnt - 1;
            end
            s2_yellow: begin
                if (pass_request && cnt >= 5)
                    state <= s3_green;
                else if (cnt == 0)
                    state <= s2_yellow;
                    cnt <= cnt - 1;
            end
            s3_green: begin
                if (pass_request && cnt >= 60)
                    state <= idle;
                else if (cnt == 0)
                    state <= s3_green;
                    cnt <= cnt - 1;
            end
        endcase
    end
end

assign clock = cnt;
assign red = state == s1_red ? 1'b1 : 1'b0;
assign yellow = state == s2_yellow ? 1'b1 : 1'b0;
assign green = state == s3_green ? 1'b1 : 1'b0;

endmodule
